/**
 * Syncs build-time content from the repo root into the docs app.
 *
 * The canonical markdown lives in documentation/ and the images in gallery/ —
 * both referenced from many places in the repo (CLAUDE.md, READMEs, configs),
 * so they are copied here at build time rather than moved or duplicated in git.
 *
 * Convention: committed pages are `.mdx`; every `content/**\/*.md` file is
 * generated by this script and gitignored wholesale (see docs/.gitignore).
 * Stale generated pages are wiped before each sync, so removing an entry from
 * PAGES removes its page.
 *
 * Runs automatically via the predev/prebuild npm hooks.
 */
import { cpSync, mkdirSync, readdirSync, readFileSync, rmSync, writeFileSync } from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const docsRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..')
const repoRoot = path.resolve(docsRoot, '..')

const GITHUB_BLOB = 'https://github.com/Giacomo-De-Luca/embedding-orrery/blob/main'

// Curated public docs: repo-relative source -> docs-relative destination.
const PAGES = {
  'documentation/DOCKER.md': 'content/docker.md',
  'documentation/DATABASE_ARCHITECTURE.md': 'content/architecture/database.md',
  'documentation/PROJECTION_FIDELITY.md': 'content/architecture/projection-fidelity.md',
  'documentation/TOPIC_QUALITY_METRICS.md': 'content/architecture/topic-quality.md',
  'documentation/SAE_ARCHITECTURE.md': 'content/sae/architecture.md',
  'documentation/SAE_PIPELINE.md': 'content/sae/pipeline.md',
  'documentation/INTERPRET_API.md': 'content/sae/interpret-api.md',
  'documentation/GLASGOW_PSYCHOLINGUISTIC_PROBING.md': 'content/case-studies/glasgow-probing.md',
  'documentation/LABEL_PLACEMENT_GUIDE.md': 'content/visualization/label-placement.md',
  'documentation/NEBULA_CLUSTER_EFFECTS.md': 'content/visualization/nebula-effects.md'
}

for (const dest of Object.values(PAGES)) {
  if (!dest.startsWith('content/') || !dest.endsWith('.md')) {
    throw new Error(
      `PAGES destination "${dest}" must be a .md file under content/ — ` +
        'generated pages are .md (gitignored), committed pages are .mdx'
    )
  }
}

const galleryDest = path.join(docsRoot, 'public/gallery')
rmSync(galleryDest, { recursive: true, force: true })
cpSync(path.join(repoRoot, 'gallery'), galleryDest, { recursive: true })

function* mdFiles(dir) {
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const entryPath = path.join(dir, entry.name)
    if (entry.isDirectory()) yield* mdFiles(entryPath)
    else if (entry.name.endsWith('.md')) yield entryPath
  }
}
for (const stale of [...mdFiles(path.join(docsRoot, 'content'))]) rmSync(stale)

// Links the rewrite below doesn't cover (./x, bare other-doc.md, ../../x, …)
// would silently 404 on the site — surface them at build time instead.
const RELATIVE_LINK = /\]\((?!https?:\/\/|\/|#|mailto:)[^)]+\)/g

for (const [src, dest] of Object.entries(PAGES)) {
  let text = readFileSync(path.join(repoRoot, src), 'utf8')
  // Repo-relative links (../foo) don't resolve on the website — point them at GitHub.
  text = text.replaceAll('](../', `](${GITHUB_BLOB}/`)
  const suspectLinks = text.match(RELATIVE_LINK)
  if (suspectLinks) {
    console.warn(`[sync-content] ${src}: relative links that will not resolve on the site:`)
    for (const link of suspectLinks) console.warn(`  ${link}`)
  }
  const destPath = path.join(docsRoot, dest)
  mkdirSync(path.dirname(destPath), { recursive: true })
  writeFileSync(destPath, text)
}

console.log(`Synced gallery/ and ${Object.keys(PAGES).length} pages from documentation/`)
